import { wipe as remotionWipe, type WipeProps as RemotionWipeProps } from '@remotion/transitions/wipe';
import type { TransitionPresentation } from '@remotion/transitions';
import { wipeSchema, type WipeOptions } from './schema';

export { wipeSchema, type WipeOptions };

// Remotion's wipe supports 8 directions including diagonals. Onda caps
// at 4 cardinals — diagonals tend to read as "PowerPoint slide
// transition" rather than deliberate motion. Add the diagonals if a
// concrete use case shows up.
const DIRECTION_MAP = {
  left: 'from-right',
  right: 'from-left',
  up: 'from-bottom',
  down: 'from-top',
} as const;

/**
 * A hard-edged wipe between two scenes — incoming scene reveals from
 * one edge to the opposite as a moving boundary. Sharper feel than
 * `slide` or `crossFade`; works well when the cut needs to read as a
 * deliberate transition.
 *
 * Pair with the recommended Onda timing for the house feel:
 * `linearTiming({ durationInFrames: 18, easing: Easing.bezier(0.16, 1, 0.3, 1) })`
 *
 * Wraps Remotion's `wipe()`.
 */
export function wipe(
  options?: WipeOptions,
): TransitionPresentation<RemotionWipeProps> {
  const opts = wipeSchema.parse(options ?? {});
  return remotionWipe({ direction: DIRECTION_MAP[opts.direction] });
}

export default wipe;

import { z } from 'zod';

/** Zod schema for {@link wipe} options. */
export const wipeSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('wipe').default('wipe'),
  /** Which direction the wipe travels across the screen. */
  direction: z.enum(['left', 'right', 'up', 'down']).default('left'),
});

export type WipeOptions = z.input<typeof wipeSchema>;

# wipe

A hard-edged wipe between two scenes. The incoming scene reveals from one edge to the opposite as a moving boundary — sharper than `slide` or `crossFade`, useful when the cut needs to read as a deliberate transition.

## Options

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `direction` | `'left' \| 'right' \| 'up' \| 'down'` | `'left'` | Direction the wipe boundary travels. `'left'` means the boundary moves leftward, revealing the new scene as it goes. |

## Usage

```tsx
import { Easing } from 'remotion';
import { TransitionSeries, linearTiming } from '@remotion/transitions';
import { wipe } from './components/onda/transitions/wipe/wipe';

<TransitionSeries.Transition
  presentation={wipe({ direction: 'left' })}
  timing={linearTiming({
    durationInFrames: 18,
    easing: Easing.bezier(0.16, 1, 0.3, 1),
  })}
/>
```

## Composition notes

- **Cardinal directions only.** Remotion's `wipe()` supports 8 directions including diagonals (`from-top-left` etc.); Onda caps at 4 because diagonals tend to read as PowerPoint-y rather than deliberate. If a concrete use case for diagonals shows up, the wrapper can be extended.
- **Hard edge by default.** The wipe's boundary is sharp. For a softer edge, use `crossFade` instead.
- **Pair with the house timing** — `linearTiming({ durationInFrames: 18, easing: Easing.bezier(0.16, 1, 0.3, 1) })` keeps the cut in the same rhythm as Onda's scene entrances.
